# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from web3 import Web3
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/authenticate', methods=['POST'])
def authenticate():
    data = request.json
    message = data['message']
    signature = data['signature']

    # Assuming Ethereum mainnet provider
    web3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_API_KEY'))

    # Recover address from signature and message
    address = web3.eth.account.recover_message(message.encode('utf-8'), signature)

    # Check if recovered address is valid
    if address:
        return jsonify({'status': 'authenticated', 'address': address})
    else:
        return jsonify({'status': 'failed', 'message': 'Invalid signature or message'}), 401

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)